import { parseServerFormsValue } from '../../models/server/forms/value.js';
import { serverCreateItemRequestSchema } from '../../schemas/server/items/create.js';
import { parse } from '../../utils/json.js';
import { handleError } from '../error.js';
export const createServerCreateItemRouteHandler = (group) => async ({ req, res, localize, ctx }) => {
    if (!group.createHandler) {
        res.status(404).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, serverCreateItemRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    const value = parseServerFormsValue(Object.fromEntries(new URLSearchParams(request.values)), group.creates);
    if (!value) {
        res.status(400).end();
        return;
    }
    const response = await group.createHandler({ ...ctx, value });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
